head.b:skin:
/* ========================================
   MERSİN MANŞET - Premium News CSS
   ======================================== */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
:root {
  --red: #d60101; --red-dark: #a80000;
  --blue: #1565c0; --green: #2e7d32;
  --orange: #e65100; --purple: #6a1b9a; --teal: #00695c;
  --bg: #f4f5f7; --white: #ffffff;
  --gray-50: #fafafa; --gray-100: #f0f0f0; --gray-200: #e0e0e0;
  --gray-400: #9e9e9e; --gray-600: #616161; --gray-800: #212121;
  --text: #1a1a2e; --text-light: #555570; --border: #e2e4e9;
  --nav-bg: #d60101; --footer-bg: #0d0d1a;
  --shadow-sm: 0 1px 4px rgba(0,0,0,0.08);
  --shadow: 0 4px 16px rgba(0,0,0,0.10);
  --shadow-md: 0 8px 32px rgba(0,0,0,0.14);
  --radius: 8px; --radius-lg: 14px;
  --font-body: 'Inter', sans-serif; --font-head: 'Merriweather', serif;
  --transition: 0.22s ease;
}
html { scroll-behavior: smooth; }
body { font-family: var(--font-body); font-size: 15px; color: var(--text); background: var(--bg); line-height: 1.6; }
a { color: inherit; text-decoration: none; transition: color var(--transition); }
img { max-width: 100%; display: block; }
ul, ol { list-style: none; }
.container { max-width: 1280px; margin: 0 auto; padding: 0 16px; }

/* SON DAKİKA */
.son-dakika { background: linear-gradient(90deg,#d60101,#a80000); color:#fff; overflow:hidden; height:36px; position:sticky; top:0; z-index:1000; box-shadow:0 2px 8px rgba(214,1,1,0.35); }
.son-dakika-inner { display:flex; align-items:center; height:100%; max-width:1280px; margin:0 auto; padding:0 16px; overflow:hidden; }
.sd-badge { background:rgba(0,0,0,0.25); color:#fff; font-weight:800; font-size:11px; letter-spacing:1.2px; padding:4px 14px; border-radius:3px; white-space:nowrap; flex-shrink:0; margin-right:18px; display:flex; align-items:center; gap:6px; }
.sd-ticker-wrap { flex:1; overflow:hidden; }
.sd-ticker { display:flex; white-space:nowrap; animation:tickerScroll 32s linear infinite; font-size:13px; font-weight:500; }
@keyframes tickerScroll { 0%{transform:translateX(0)} 100%{transform:translateX(-50%)} }

/* TOP BAR */
.top-bar { background:var(--gray-50); border-bottom:1px solid var(--border); font-size:12px; color:var(--gray-600); }
.top-bar-inner { display:flex; justify-content:space-between; align-items:center; height:36px; }
.top-bar-left { display:flex; align-items:center; gap:18px; }
.top-bar-right { display:flex; align-items:center; gap:10px; }
.top-bar-right a { color:var(--gray-600); font-size:14px; transition:color var(--transition); }
.top-bar-right a:hover { color:var(--red); }
.rss-btn { background:var(--orange); color:#fff !important; padding:3px 10px; border-radius:3px; font-size:11px; font-weight:700; }

/* LOGO BAR */
.logo-bar { background:var(--white); border-bottom:2px solid var(--red); padding:12px 0; }
.logo-bar-inner { display:flex; align-items:center; justify-content:space-between; gap:20px; }
.site-logo { display:flex; align-items:center; gap:10px; flex-shrink:0; }
.logo-icon { width:48px; height:48px; background:var(--red); color:#fff; border-radius:10px; display:flex; align-items:center; justify-content:center; font-size:22px; box-shadow:0 4px 12px rgba(214,1,1,0.3); transition:transform var(--transition); }
.site-logo:hover .logo-icon { transform:scale(1.08); }
.logo-text { display:flex; flex-direction:column; line-height:1; }
.logo-main { font-family:var(--font-head); font-size:22px; font-weight:900; color:var(--red); letter-spacing:2px; }
.logo-sub { font-family:var(--font-head); font-size:11px; font-weight:400; color:var(--gray-600); letter-spacing:3px; text-transform:uppercase; }
.search-box { display:flex; align-items:center; background:var(--gray-100); border:1.5px solid var(--border); border-radius:6px; overflow:hidden; transition:border-color var(--transition); }
.search-box:focus-within { border-color:var(--red); box-shadow:0 0 0 3px rgba(214,1,1,0.10); }
.search-box input { border:none; background:transparent; padding:9px 14px; font-size:13px; width:200px; outline:none; color:var(--text); font-family:var(--font-body); }
.search-box button { border:none; background:var(--red); color:#fff; padding:9px 16px; cursor:pointer; font-size:14px; transition:background var(--transition); }
.search-box button:hover { background:var(--red-dark); }

/* NAV */
.main-nav { background:var(--nav-bg); box-shadow:0 4px 16px rgba(214,1,1,0.25); }
.main-nav .container { display:flex; align-items:center; }
.nav-menu { display:flex; flex-wrap:nowrap; overflow-x:auto; scrollbar-width:none; gap:0; padding:0; width:100%; }
.nav-menu::-webkit-scrollbar { display:none; }
.nav-item { position:relative; flex-shrink:0; }
.nav-link { display:flex; align-items:center; gap:5px; color:rgba(255,255,255,0.88); font-size:13.5px; font-weight:600; padding:13px 14px; transition:background var(--transition); white-space:nowrap; }
.nav-link:hover, .nav-item.active .nav-link { color:#fff; background:rgba(0,0,0,0.22); }
.nav-video .nav-link { color:#ffeb3b; }
.nav-galeri .nav-link { color:#ff9800; }
.dropdown-menu { position:absolute; top:100%; left:0; background:#fff; border-radius:0 0 var(--radius) var(--radius); box-shadow:var(--shadow-md); min-width:180px; z-index:500; padding:8px 0; opacity:0; pointer-events:none; transform:translateY(-8px); transition:opacity 0.2s,transform 0.2s; }
.dropdown:hover .dropdown-menu { opacity:1; pointer-events:all; transform:translateY(0); }
.dropdown-menu li a { display:block; padding:9px 18px; font-size:13px; font-weight:500; color:var(--text); transition:background var(--transition); }
.dropdown-menu li a:hover { background:var(--gray-100); color:var(--red); }
.hamburger { display:none; flex-direction:column; justify-content:center; gap:5px; background:none; border:none; cursor:pointer; padding:12px; margin-left:auto; }
.hamburger span { display:block; width:24px; height:2px; background:#fff; border-radius:2px; transition:all 0.3s; }

/* LAYOUT */
#main-content { padding:24px 0 32px; }
.content-grid { display:grid; grid-template-columns:1fr 320px; gap:24px; align-items:start; }

/* HERO */
.hero-carousel { display:grid; grid-template-columns:1fr 280px; gap:0; border-radius:var(--radius-lg); overflow:hidden; box-shadow:var(--shadow-md); margin-bottom:28px; background:#000; }
.carousel-container { position:relative; overflow:hidden; background:#111; }
.carousel-track { display:flex; transition:transform 0.55s cubic-bezier(0.4,0,0.2,1); will-change:transform; }
.carousel-slide { min-width:100%; position:relative; }
.carousel-slide a { display:block; position:relative; }
.slide-img-wrap { position:relative; aspect-ratio:16/9; overflow:hidden; }
.slide-img { width:100%; height:100%; object-fit:cover; display:block; transition:transform 0.6s ease; }
.carousel-slide:hover .slide-img { transform:scale(1.03); }
.slide-overlay { position:absolute; inset:0; background:linear-gradient(0deg,rgba(0,0,0,0.82) 0%,rgba(0,0,0,0.25) 55%,transparent 100%); }
.slide-caption { position:absolute; bottom:0; left:0; right:0; padding:18px 20px 20px; color:#fff; }
.slide-category { display:inline-block; background:var(--red); color:#fff; font-size:10px; font-weight:800; letter-spacing:1.2px; padding:3px 10px; border-radius:3px; margin-bottom:8px; text-transform:uppercase; }
.slide-caption h2 { font-family:var(--font-head); font-size:16px; font-weight:700; line-height:1.4; margin-bottom:6px; text-shadow:0 2px 8px rgba(0,0,0,0.5); display:-webkit-box; -webkit-line-clamp:3; -webkit-box-orient:vertical; overflow:hidden; }
.slide-time { font-size:11px; opacity:0.8; display:flex; align-items:center; gap:4px; }
.carousel-btn { position:absolute; top:50%; transform:translateY(-50%); background:rgba(0,0,0,0.55); color:#fff; border:none; width:36px; height:36px; border-radius:50%; cursor:pointer; display:flex; align-items:center; justify-content:center; font-size:14px; z-index:10; transition:background var(--transition); backdrop-filter:blur(4px); }
.carousel-btn:hover { background:var(--red); transform:translateY(-50%) scale(1.08); }
.carousel-prev { left:10px; }
.carousel-next { right:10px; }
.carousel-indicators { position:absolute; bottom:14px; left:50%; transform:translateX(-50%); display:flex; gap:6px; z-index:10; }
.indicator { width:28px; height:3px; background:rgba(255,255,255,0.4); border:none; border-radius:2px; cursor:pointer; transition:background var(--transition),width var(--transition); padding:0; }
.indicator.active { background:#fff; width:42px; }

/* SIDE NEWS */
.hero-side-news { background:#fff; border-left:1px solid var(--border); display:flex; flex-direction:column; overflow:hidden; }
.side-news-item { display:flex; gap:10px; padding:12px 14px; border-bottom:1px solid var(--gray-100); transition:background var(--transition); align-items:flex-start; }
.side-news-item:last-child { border-bottom:none; }
.side-news-item:hover { background:var(--gray-50); }
.side-news-item img { width:90px; height:60px; object-fit:cover; border-radius:5px; flex-shrink:0; }
.side-news-text { flex:1; min-width:0; }
.side-cat { display:inline-block; background:var(--red); color:#fff; font-size:9px; font-weight:800; padding:2px 7px; border-radius:2px; margin-bottom:4px; text-transform:uppercase; }
.side-news-text p { font-size:12px; font-weight:600; line-height:1.4; color:var(--text); display:-webkit-box; -webkit-line-clamp:2; -webkit-box-orient:vertical; overflow:hidden; margin-bottom:4px; }
.side-news-item:hover .side-news-text p { color:var(--red); }
.side-time { font-size:10px; color:var(--gray-400); display:flex; align-items:center; gap:3px; }

/* SECTIONS */
.news-section { margin-bottom:28px; }
.section-header { display:flex; align-items:center; justify-content:space-between; margin-bottom:16px; border-bottom:3px solid var(--red); padding-bottom:10px; }
.section-title span { background:var(--red); color:#fff; padding:4px 16px; border-radius:4px; display:inline-block; font-size:13px; font-weight:800; letter-spacing:0.5px; text-transform:uppercase; }
.section-title.spor span { background:var(--green); }
.section-title.ekonomi span { background:var(--blue); }
.section-title.egitim span { background:var(--purple); }
.section-title.saglik span { background:var(--teal); }
.section-title.dunya span { background:var(--orange); }
.see-all { font-size:12px; font-weight:700; color:var(--red); display:flex; align-items:center; gap:5px; transition:gap var(--transition); text-transform:uppercase; }
.see-all:hover { gap:9px; }

/* CARDS */
.news-grid { display:grid; grid-template-columns:repeat(3,1fr); gap:14px; }
.news-grid-3 { grid-template-columns:repeat(3,1fr); }
.news-card-large { grid-column:1/-1; display:grid; grid-template-columns:1.8fr 1fr; }
.news-card-large .news-card-img-wrap { border-radius:var(--radius) 0 0 var(--radius); overflow:hidden; }
.news-card-large .news-card-img { height:100%; }
.news-card-large .news-card-body { padding:24px; display:flex; flex-direction:column; justify-content:center; border-radius:0 var(--radius) var(--radius) 0; }
.news-card-large .news-card-body h3 { font-family:var(--font-head); font-size:18px; font-weight:700; line-height:1.4; margin-bottom:10px; }
.news-card-excerpt { font-size:13px; color:var(--text-light); line-height:1.6; margin-bottom:14px; display:-webkit-box; -webkit-line-clamp:3; -webkit-box-orient:vertical; overflow:hidden; }
.news-card { background:var(--white); border-radius:var(--radius); overflow:hidden; box-shadow:var(--shadow-sm); transition:transform var(--transition),box-shadow var(--transition); }
.news-card:hover { transform:translateY(-3px); box-shadow:var(--shadow-md); }
.news-card a { display:block; height:100%; }
.news-card-img-wrap { position:relative; overflow:hidden; aspect-ratio:16/9; }
.news-card-img { width:100%; height:100%; object-fit:cover; transition:transform 0.4s ease; }
.news-card:hover .news-card-img { transform:scale(1.06); }
.news-card-cat { position:absolute; top:10px; left:10px; background:var(--red); color:#fff; font-size:9px; font-weight:800; padding:3px 9px; border-radius:3px; text-transform:uppercase; z-index:1; }
.ekon-cat { background:var(--blue) !important; }
.news-card-body { padding:14px 16px 16px; background:var(--white); }
.news-card-body h3 { font-size:14px; font-weight:700; line-height:1.45; color:var(--text); margin-bottom:10px; display:-webkit-box; -webkit-line-clamp:3; -webkit-box-orient:vertical; overflow:hidden; transition:color var(--transition); }
.news-card:hover .news-card-body h3 { color:var(--red); }
.news-card-meta { display:flex; align-items:center; gap:14px; font-size:11px; color:var(--gray-400); }

/* LIST */
.news-list { background:var(--white); border-radius:var(--radius); overflow:hidden; box-shadow:var(--shadow-sm); }
.news-list-item { border-bottom:1px solid var(--gray-100); transition:background var(--transition); }
.news-list-item:last-child { border-bottom:none; }
.news-list-item:hover { background:var(--gray-50); }
.news-list-item a { display:flex; gap:14px; padding:14px 16px; align-items:center; }
.news-list-item img { width:110px; height:74px; object-fit:cover; border-radius:6px; flex-shrink:0; transition:transform 0.3s; }
.news-list-item:hover img { transform:scale(1.04); }
.news-list-text { flex:1; min-width:0; }
.list-cat { display:inline-block; font-size:9px; font-weight:800; padding:2px 8px; border-radius:2px; text-transform:uppercase; margin-bottom:5px; background:var(--red); color:#fff; }
.spor-cat { background:var(--green) !important; }
.dunya-cat { background:var(--orange) !important; }
.news-list-text h3 { font-size:13.5px; font-weight:600; line-height:1.45; color:var(--text); display:-webkit-box; -webkit-line-clamp:2; -webkit-box-orient:vertical; overflow:hidden; margin-bottom:5px; transition:color var(--transition); }
.news-list-item:hover .news-list-text h3 { color:var(--red); }
.list-time { font-size:11px; color:var(--gray-400); display:flex; align-items:center; gap:4px; }
.news-list.compact .news-list-item a { padding:10px 14px; }
.news-list.compact .news-list-item img { width:80px; height:54px; border-radius:4px; }
.two-col { display:grid; grid-template-columns:1fr 1fr; gap:20px; }

/* AD */
.ad-banner { height:90px; background:repeating-linear-gradient(45deg,var(--gray-100),var(--gray-100) 10px,var(--gray-200) 10px,var(--gray-200) 20px); display:flex; align-items:center; justify-content:center; color:var(--gray-400); font-size:12px; letter-spacing:2px; text-transform:uppercase; border-radius:var(--radius); margin-bottom:28px; }

/* SIDEBAR */
.sidebar-col { position:sticky; top:60px; display:flex; flex-direction:column; gap:20px; }
.sidebar-widget { background:var(--white); border-radius:var(--radius); overflow:hidden; box-shadow:var(--shadow-sm); }
.widget-header { background:linear-gradient(135deg,var(--gray-800),#2d2d4e); color:#fff; padding:12px 16px; }
.widget-header h3 { font-size:13px; font-weight:700; display:flex; align-items:center; gap:8px; }
.popular-list { padding:6px 0; }
.popular-item { border-bottom:1px solid var(--gray-100); transition:background var(--transition); }
.popular-item:last-child { border-bottom:none; }
.popular-item:hover { background:var(--gray-50); }
.popular-item a { display:flex; align-items:flex-start; gap:12px; padding:10px 14px; }
.pop-num { width:24px; height:24px; background:var(--red); color:#fff; border-radius:4px; display:flex; align-items:center; justify-content:center; font-size:11px; font-weight:800; flex-shrink:0; margin-top:1px; }
.popular-item:nth-child(4) .pop-num { background:var(--blue); }
.popular-item:nth-child(5) .pop-num { background:var(--gray-600); }
.pop-content p { font-size:12.5px; font-weight:600; line-height:1.4; color:var(--text); margin-bottom:4px; display:-webkit-box; -webkit-line-clamp:2; -webkit-box-orient:vertical; overflow:hidden; transition:color var(--transition); }
.popular-item:hover .pop-content p { color:var(--red); }
.pop-content span { font-size:10px; color:var(--gray-400); display:flex; align-items:center; gap:3px; }
.weather-widget .widget-header { background:linear-gradient(135deg,#1565c0,#0d47a1); }
.weather-content { padding:16px; }
.weather-main { display:flex; align-items:center; gap:16px; margin-bottom:14px; }
.weather-icon-big { font-size:42px; color:#ffc107; }
.weather-temp { font-size:36px; font-weight:800; line-height:1; }
.weather-city { font-size:13px; font-weight:700; }
.weather-desc { font-size:12px; color:var(--gray-600); }
.weather-days { display:grid; grid-template-columns:repeat(4,1fr); gap:6px; border-top:1px solid var(--border); padding-top:12px; }
.weather-day { display:flex; flex-direction:column; align-items:center; gap:4px; font-size:11px; color:var(--gray-600); }
.weather-day i { font-size:18px; color:#ffc107; }
.weather-day span:last-child { font-weight:700; color:var(--text); }
.duyuru-list { padding:6px 0; }
.duyuru-list li { border-bottom:1px solid var(--gray-100); transition:background var(--transition); }
.duyuru-list li:last-child { border-bottom:none; }
.duyuru-list li:hover { background:var(--gray-50); }
.duyuru-list li a { display:flex; align-items:center; gap:8px; padding:10px 14px; font-size:12.5px; font-weight:500; color:var(--text); }
.duyuru-list li a i { color:var(--blue); font-size:13px; }
.duyuru-list li:hover a { color:var(--red); }
.kur-widget .widget-header { background:linear-gradient(135deg,#2e7d32,#1b5e20); }
.kur-list { padding:6px 0; }
.kur-item { display:flex; align-items:center; justify-content:space-between; padding:10px 16px; border-bottom:1px solid var(--gray-100); font-size:13px; }
.kur-item:last-child { border-bottom:none; }
.kur-name { display:flex; align-items:center; gap:6px; color:var(--text); font-weight:600; }
.kur-val { font-weight:800; font-size:14px; }
.kur-change { font-size:11px; font-weight:700; display:flex; align-items:center; gap:2px; min-width:56px; justify-content:flex-end; }
.kur-change.up { color:#2e7d32; }
.kur-change.down { color:#c62828; }
.kur-update { font-size:10px; color:var(--gray-400); padding:8px 16px; border-top:1px solid var(--gray-100); }
.social-follow-grid { display:grid; grid-template-columns:1fr 1fr; }
.follow-btn { display:flex; flex-direction:column; align-items:center; justify-content:center; padding:16px 10px; gap:4px; transition:opacity var(--transition); border:1px solid rgba(255,255,255,0.1); color:#fff; }
.follow-btn:hover { opacity:0.85; }
.follow-btn.fb { background:#1877f2; }
.follow-btn.tw { background:#000000; }
.follow-btn.ig { background:linear-gradient(135deg,#f09433,#e6683c,#dc2743,#cc2366,#bc1888); }
.follow-btn.yt { background:#ff0000; }
.follow-btn i { font-size:22px; }
.follow-btn span { font-size:11px; font-weight:700; }
.follow-btn em { font-size:10px; font-style:normal; opacity:0.8; }

/* FOOTER */
.site-footer { background:var(--footer-bg); margin-top:40px; }
.footer-top { padding:48px 0 40px; border-bottom:1px solid rgba(255,255,255,0.06); }
.footer-grid { display:grid; grid-template-columns:2fr 1fr 1fr 1fr; gap:32px; }
.footer-col h4 { color:#fff; font-size:13px; font-weight:800; text-transform:uppercase; letter-spacing:1.5px; margin-bottom:18px; padding-bottom:10px; border-bottom:2px solid var(--red); display:inline-block; }
.footer-about .footer-logo { display:flex; align-items:center; gap:10px; margin-bottom:16px; }
.footer-about p { color:rgba(255,255,255,0.55); font-size:13px; line-height:1.7; margin-bottom:20px; }
.footer-social { display:flex; gap:10px; }
.footer-social a { width:36px; height:36px; border-radius:8px; background:rgba(255,255,255,0.08); display:flex; align-items:center; justify-content:center; color:rgba(255,255,255,0.7); font-size:15px; transition:background var(--transition),transform var(--transition); }
.footer-social a:hover { background:var(--red); color:#fff; transform:translateY(-2px); }
.footer-col ul li { margin-bottom:10px; }
.footer-col ul li a { color:rgba(255,255,255,0.55); font-size:13px; transition:color var(--transition); }
.footer-col ul li a:hover { color:#fff; }
.footer-bottom { background:#141428; padding:16px 0; }
.footer-bottom-inner { display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:10px; }
.footer-bottom p { font-size:12px; color:rgba(255,255,255,0.4); }
.footer-bottom a { color:var(--red); font-weight:600; }
.back-to-top { position:fixed; bottom:24px; right:24px; width:44px; height:44px; border-radius:50%; background:var(--red); color:#fff; border:none; cursor:pointer; font-size:16px; display:flex; align-items:center; justify-content:center; box-shadow:0 4px 20px rgba(214,1,1,0.5); transition:transform var(--transition),opacity var(--transition); opacity:0; pointer-events:none; z-index:900; }
.back-to-top.visible { opacity:1; pointer-events:all; }
.back-to-top:hover { background:var(--red-dark); transform:translateY(-3px) scale(1.08); }

/* BLOGGER POST LIST */
.blog-posts-section { margin-bottom:28px; }
.blog-post-card { background:var(--white); border-radius:var(--radius); overflow:hidden; box-shadow:var(--shadow-sm); margin-bottom:16px; transition:transform var(--transition),box-shadow var(--transition); }
.blog-post-card:hover { transform:translateY(-3px); box-shadow:var(--shadow-md); }
.blog-post-card .post-header { display:grid; grid-template-columns:280px 1fr; }
.blog-post-card .post-img-wrap { overflow:hidden; aspect-ratio:16/9; }
.blog-post-card .post-img { width:100%; height:100%; object-fit:cover; transition:transform 0.4s; }
.blog-post-card:hover .post-img { transform:scale(1.05); }
.blog-post-card .post-body { padding:20px 24px; display:flex; flex-direction:column; justify-content:center; }
.blog-post-card .post-meta { display:flex; align-items:center; gap:12px; font-size:11px; color:var(--gray-400); margin-bottom:8px; }
.blog-post-card .post-cat { background:var(--red); color:#fff; font-size:9px; font-weight:800; padding:2px 8px; border-radius:2px; text-transform:uppercase; }
.blog-post-card h2.post-title { font-family:var(--font-head); font-size:17px; font-weight:700; line-height:1.4; color:var(--text); margin-bottom:8px; transition:color var(--transition); }
.blog-post-card:hover h2.post-title { color:var(--red); }
.blog-post-card .post-snippet { font-size:13px; color:var(--text-light); line-height:1.6; display:-webkit-box; -webkit-line-clamp:2; -webkit-box-orient:vertical; overflow:hidden; }
.blog-post-card .read-more { display:inline-flex; align-items:center; gap:6px; margin-top:12px; font-size:12px; font-weight:700; color:var(--red); transition:gap var(--transition); }
.blog-post-card:hover .read-more { gap:10px; }

/* RESPONSIVE */
@media(max-width:1100px) {
  .hero-carousel { grid-template-columns:1fr; }
  .hero-side-news { display:grid; grid-template-columns:repeat(3,1fr); border-left:none; border-top:1px solid var(--border); }
}
@media(max-width:900px) {
  .content-grid { grid-template-columns:1fr; }
  .sidebar-col { position:static; display:grid; grid-template-columns:1fr 1fr; }
  .news-grid { grid-template-columns:1fr 1fr; }
  .news-card-large { grid-column:1/-1; grid-template-columns:1fr; }
  .footer-grid { grid-template-columns:1fr 1fr; }
}
@media(max-width:720px) {
  .hamburger { display:flex; }
  .nav-menu { display:none; flex-direction:column; position:absolute; top:100%; left:0; right:0; background:#b00000; z-index:200; padding:10px 0; }
  .nav-menu.open { display:flex; }
  .hero-side-news { grid-template-columns:1fr 1fr; }
  .two-col { grid-template-columns:1fr; }
  .sidebar-col { grid-template-columns:1fr; }
}
@media(max-width:560px) {
  .news-grid { grid-template-columns:1fr; }
  .footer-grid { grid-template-columns:1fr; }
  .blog-post-card .post-header { grid-template-columns:1fr; }
}

body.script:
//
document.addEventListener('DOMContentLoaded', function() {
  // Tarih
  var d = new Date();
  var opts = {weekday:'long',year:'numeric',month:'long',day:'numeric'};
  var el = document.getElementById('currentDate');
  if(el) el.textContent = d.toLocaleDateString('tr-TR', opts);

  // Footer yılı
  var fy = document.getElementById('footerYear');
  if(fy) fy.textContent = d.getFullYear();

  // Kur saati
  var kt = document.getElementById('kurTime');
  if(kt) kt.textContent = d.toLocaleTimeString('tr-TR',{hour:'2-digit',minute:'2-digit'});

  // Ticker duplikasyon
  var ticker = document.getElementById('sdTicker');
  if(ticker) ticker.innerHTML += ticker.innerHTML;

  // Hamburger
  var ham = document.getElementById('hamburger');
  var nav = document.getElementById('navMenu');
  if(ham && nav) {
    ham.addEventListener('click', function() {
      var open = nav.classList.toggle('open');
      ham.setAttribute('aria-expanded', open.toString());
    });
    document.addEventListener('click', function(e) {
      if(!ham.contains(e.target) && !nav.contains(e.target)) {
        nav.classList.remove('open');
      }
    });
  }

  // Back to top
  var btt = document.getElementById('backToTop');
  if(btt) {
    window.addEventListener('scroll', function() {
      btt.classList.toggle('visible', window.scrollY > 400);
    }, {passive:true});
    btt.addEventListener('click', function() {
      window.scrollTo({top:0, behavior:'smooth'});
    });
  }

  // Arama
  var sb = document.getElementById('search-btn');
  var si = document.getElementById('search-input');
  if(sb && si) {
    sb.addEventListener('click', function() {
      var q = si.value.trim();
      if(q) window.location.href = '/search?q=' + encodeURIComponent(q);
    });
    si.addEventListener('keydown', function(e) {
      if(e.key === 'Enter') sb.click();
    });
  }

  // Fade-in
  if('IntersectionObserver' in window) {
    var obs = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if(entry.isIntersecting) {
          entry.target.style.opacity = '1';
          entry.target.style.transform = 'translateY(0)';
          obs.unobserve(entry.target);
        }
      });
    }, {threshold:0.08});
    document.querySelectorAll('.blog-post-card,.sidebar-widget').forEach(function(el) {
      el.style.opacity = '0';
      el.style.transform = 'translateY(18px)';
      el.style.transition = 'opacity 0.5s ease,transform 0.5s ease';
      obs.observe(el);
    });
  }

  // Kur simülasyonu
  function simKur() {
    [{id:'kur-dolar',base:38.42},{id:'kur-euro',base:41.87},{id:'kur-gbp',base:48.65}].forEach(function(item) {
      var el = document.getElementById(item.id);
      if(!el) return;
      var v = el.querySelector('.kur-val');
      var c = el.querySelector('.kur-change');
      if(!v||!c) return;
      var d = (Math.random()*0.04-0.02);
      var nv = (item.base+d).toFixed(2);
      var pct = ((d/item.base)*100).toFixed(2);
      var up = d>=0;
      v.textContent = nv;
      c.innerHTML = '<i class="fa-solid fa-caret-'+(up?'up':'down')+'"></i> '+(up?'+':'')+pct+'%';
      c.className = 'kur-change '+(up?'up':'down');
    });
    var kt2 = document.getElementById('kurTime');
    if(kt2) kt2.textContent = new Date().toLocaleTimeString('tr-TR',{hour:'2-digit',minute:'2-digit'});
  }
  setInterval(simKur, 8000);
});
//
